   548→void GrpcMuxImpl::queueDiscoveryRequest(absl::string_view queue_item) {
   549→  if (!grpc_stream_->grpcStreamAvailable()) {
   550→    ENVOY_LOG(debug, "No stream available to queueDiscoveryRequest for {}", queue_item);
   551→    return; // Drop this request; the reconnect will enqueue a new one.
   552→  }
   553→  ApiState& api_state = apiStateFor(queue_item);
   554→  if (api_state.paused()) {
   555→    ENVOY_LOG(trace, "API {} paused during queueDiscoveryRequest(), setting pending.", queue_item);
   556→    api_state.pending_ = true;
   557→    return; // Drop this request; the unpause will enqueue a new one.
   558→  }
   559→  request_queue_->emplace(std::string(queue_item));
   560→  drainRequests();
   561→}

